\pard\fi0\li0\qj\ri-570\sb0\sa0\itap0 {\field{\*\fldinst HYPERLINK "hida://4665/?u"}{\fldrslt \plain \f1\lang1033\fs22\chcbpat17 1r-5r}}\plain \f1\lang1033\fs22  {\field{\*\fldinst HYPERLINK "hida://bezwrk[0].6922/?u"}{\fldrslt \plain \f1\b\lang1033\fs22\chcbpat17 Meditation zum Osterfest}}
\par \pard\fi0\li0\qj\ri-570\sb0\sa0\itap0 \plain \f1\i\lang1033\fs22 >Hier begijnt een suuerlichck\plain \f1\lang1033\fs22  (!) \plain \f1\i\lang1033\fs22 oeffeninge op den gloriose paesdach.< {\field{\*\fldinst HYPERLINK "hida://5650[0].5666v/?u"}{\fldrslt \plain \f1\i\lang1033\fs22\chcbpat17 Opten heiligen paesdach wildy nv sunderlinge verblijden vander opuerstandenysse dijns lieuen brudeg}}\plain \f1\i\lang1033\fs22 [a]ms, die als een edel zegeuechter alle sijn noet verwonnen heeft. Ende heeft sijnen lieuen wtuercaren vrijenden den hemel gewonnen mit sijns herten bloet ende bitteren doet ... Hier om, o ynnige deuoete siel, ist dattu dat liden Cristi in dijnen herten gedragen heuest ende geestelick myt gestoruen, soe saltu oec nv waerlic mit om verrysen ende dat vrolick Alleluya sijngende Die heer is waerlick opuerstaen alleluya ...\~\endash \~... op dattu dese vijertijch dage vruchtbaerlick ende salichlick toe brenghen moegest ende alle die tijt dijns leuens tot enen saligen eynde. Amen\plain \f1\lang1033\fs22 .}

{\rtf1\ansi\ansicpg0\uc1\deff0\deflang0\deflangfe0{\fonttbl{\f0\fnil\fcharset1 Arial;}{\f1\fnil\fcharset0 Arial;}{\f2\fnil\fcharset0 Calibri;}}{\colortbl;\red0\green0\blue0;\red0\green0\blue255;\red0\green255\blue255;\red0\green255\blue0;\red255\green0\blue255;\red255\green0\blue0;\red255\green255\blue0;\red255\green255\blue255;\red0\green0\blue128;\red0\green128\blue128;\red0\green128\blue0;\red128\green0\blue128;\red128\green0\blue0;\red128\green128\blue0;\red128\green128\blue128;\red192\green192\blue192;\red204\green238\blue221;}

\uc1
\pard\fi0\li0\qj\ri-570\sb0\sa0\itap0 {\field{\*\fldinst HYPERLINK "hida://4665/?u"}{\fldrslt \plain \f1\lang1033\fs22\chcbpat17 5r-5av}}\plain \f1\lang1033\fs22  {\field{\*\fldinst HYPERLINK "hida://bezwrk[0].6922/?u"}{\fldrslt \plain \f1\b\lang1033\fs22\chcbpat17 Gebet zum Osterfest}}
\par \pard\fi0\li0\qj\ri-570\sb0\sa0\itap0 {\field{\*\fldinst HYPERLINK "hida://5650[0].5666v/?u"}{\fldrslt \plain \f1\i\lang1033\fs22\chcbpat17 O alre edelste zegeuechter Ihesu Cristi}}\plain \f1\lang1033\fs22  (!)\plain \f1\i\lang1033\fs22 , dij moeten lauen van mynre wegen alle die choren der engelen ... daer om du alre heilichste der heiligen, du guedertijeren scepper, ons huyden heuest verloest by dijnre saliger opuerstandenysse, hijer om bid ic arme sundersche sijn genadicheit, dattu alle den genen die dijn hulpe ende gracie sueckende sijnt, om dese blijtschap des ouersten hoechtijts wilst verloesen van allen lagen des viants ...
\par \pard\fi0\li0\qj\ri-570\sb0\sa0\itap0 \plain \f1\lang1033\fs20 Auch in {\field{\*\fldinst HYPERLINK "hida://5007[0].501m/?u"}{\fldrslt \plain \f1\lang1033\fs20\chcbpat17 Darmstadt, ULB, Hs 992}}\plain \f1\lang1033\fs20 , Bl. 192r (\plain \f1\scaps\lang1033\fs20 Achten/Knaus\plain \f1\lang1033\fs20 , S. 82, Nr. 20).}

