\par \pard\fi0\li0\qj\ri-570\sb0\sa0\itap0 {\field{\*\fldinst HYPERLINK "hida://bezwrk[1].6930/?u"}{\fldrslt \plain \f1\lang1033\fs20\chcbpat17 Zu}}\plain \f1\lang1033\fs20  deutschsprachigen Gartenallegorien vgl. Dietrich \plain \f1\scaps\lang1033\fs20 Schmidtke\plain \f1\lang1033\fs20 , Studien zur dingallegorischen Erbauungsliteratur des Sp\u228 \'e4tmittelalters. Am Beispiel der Gartenallegorese (Hermaea N.F. 43), T\u252 \'fcbingen 1982, ohne diesen Text, auch kein n\u228 \'e4her verwandter Text unter den ebd., S. 70-73 behandelten niederl\u228 \'e4ndischen Allegorien.
\par \pard\fi0\li0\qj\ri-570\sb0\sa0\itap0 \plain \f1\lang1033\fs22 \par}

